import React, { useState } from 'react';
import './Components.css';
import './Contact.css';

const Contact = () => {
  const [formData, setFormData] = useState({ name: "", email: "", message: "" });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    
    try {
      const response = await fetch('https://api.web3forms.com/submit', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          access_key: "8c9c5c5a-e6f4-4c5a-b3d2-1f9a8b7c6d5e",
          name: formData.name,
          email: formData.email,
          message: formData.message,
          to: "andyymackay@gmail.com",
          subject: `Portfolio Contact from ${formData.name}`
        })
      });

      const result = await response.json();
      
      if (result.success) {
        setSubmitStatus('success');
        setFormData({ name: "", email: "", message: "" });
      } else {
        throw new Error('Form submission failed');
      }
    } catch (error) {
      console.error('Form submission error:', error);
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
      // Reset status after 5 seconds
      setTimeout(() => setSubmitStatus(null), 5000);
    }
  };

  return (
    <div className="contact-section">
      <div className="contact-scanline-layer">
  <div className="contact-scanline fuzz" style={{ top: '15%' }} />
  <div className="contact-scanline blue" style={{ top: '40%' }} />
  <div className="contact-scanline fuzz" style={{ top: '70%' }} />
      </div>
      <div className="contact-card">
        <h2>Contact Me</h2>
        {submitStatus === 'success' && (
          <div className="form-message success">
            Message sent successfully! I'll get back to you soon.
          </div>
        )}
        {submitStatus === 'error' && (
          <div className="form-message error">
            Failed to send message. Please try again.
          </div>
        )}
        <form onSubmit={handleSubmit} className="contact-form">
          <div className="form-group">
            <input 
              type="text" 
              placeholder="Your Name"
              value={formData.name}
              onChange={(e) => setFormData({...formData, name: e.target.value})}
              required
              className="cyber-input"
            />
            <div className="input-glow"></div>
          </div>
          <div className="form-group">
            <input 
              type="email" 
              placeholder="Your Email"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              required
              className="cyber-input"
            />
            <div className="input-glow"></div>
          </div>
          <div className="form-group">
            <textarea 
              placeholder="Your Message"
              value={formData.message}
              onChange={(e) => setFormData({...formData, message: e.target.value})}
              required
              className="cyber-textarea"
              rows="3"
            />
            <div className="input-glow"></div>
          </div>
          <button 
            type="submit" 
            className="submit-btn"
            disabled={isSubmitting}
          >
            {isSubmitting ? (
              <>
                <span className="loading-spinner"></span>
                Sending...
              </>
            ) : (
              <>
                Send Message
                <span className="btn-glow"></span>
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Contact;
